sys_script_include.script:
var MediaUtils2 = Class.create();
MediaUtils2.prototype = {
    initialize: function() {
    },
    refQualMedia: function() {
    var moviesNoToBeShown = []  ;
    var grReview = new GlideRecord("x_153878_netflix_review");
    grReview.addEncodedQuery("opened_byDYNAMIC90d1921e5f510100a9ad2572f2b477fe^state!=4");
    grReview.query();
    while(grReview.next()) {
        moviesNoToBeShown.push(grReview.media.sys_id.toString());
    }
var moviesToBeShown = [];
var grMedias = new GlideRecord("x_153878_netflix_media");
grMedias.addQuery("state", "3");
grMedias.query();
while(grMedias.next()){
    if(moviesNoToBeShown.indexOf(grMedias.getUniqueValue()) == -1){
        moviesToBeShown.push(grMedias.getUniqueValue());
    }
}
return "sys_idIN" + moviesToBeShown.join(",");

    },

    type: 'MediaUtils2'
};
